// domain/port/in
public interface ProcessTradingRecordUseCase { void process(); }

// domain/port/out
public interface ScraperPort { ScrapedPost scrape(); }
public interface OcrPort { ParsedOrder analyze(List<byte[]> images); }
public interface SheetPort { void update(TradingRecord record); }
public interface NotifyPort { void notify(TradingRecord record); }
public interface KistaPort { void sendOrders(TradingRecord record); } // optional 연동

@Service
@RequiredArgsConstructor
public class TradingRecordService implements ProcessTradingRecordUseCase {
  private final ScraperPort scraper;
  private final OcrPort ocr;
  private final SheetPort sheet;
  private final NotifyPort notify;
  private final KistaPort kista; // @Autowired(required=false)

  @Override
  public void process() {
    ScrapedPost post = scraper.scrape();
    ParsedOrder order = ocr.analyze(post.images());
    TradingRecord record = TradingRecord.of(post, order);
    sheet.update(record);
    notify.notify(record);
    if (kista != null) {
      try { kista.sendOrders(record); }
      catch (Exception e) { log.warn("KISTA 전송 실패 (무시): {}", e.getMessage()); }
    }
  }
}

@Component
public class FandingScraperAdapter implements ScraperPort {
  // RestTemplate: 타임아웃 120초
  // SCRAPER_URL 환경변수에서 주입
  // 응답 JSON: { postTitle, postDate, postUrl, images: [base64, ...] }
  // Base64.getDecoder().decode(img) → byte[]
  // 실패 시 ScraperException throw
}

@Component
public class GeminiVisionAdapter implements OcrPort {
  // 모델: gemini-2.5-flash-lite (고정)
  // endpoint: https://generativelanguage.googleapis.com/v1beta/models/gemini-2.5-flash-lite:generateContent
  // byte[] → Base64 → inline_data (mimeType: image/png)
  // 응답 파싱: ```json 블록 먼저 시도 → 없으면 순수 JSON
  // holdings < 0 → 0 보정
  // holdings == 0 → avgPrice = null 강제
  // 실패 시 OcrException throw
}

@Component
public class GoogleSheetsAdapter implements SheetPort {
  // google-api-services-sheets 라이브러리 사용
  // 서비스 계정 JSON: GOOGLE_SERVICE_ACCOUNT_JSON_PATH 환경변수
  // Spreadsheet ID: GOOGLE_SHEETS_SPREADSHEET_ID 환경변수
  // batchUpdate: USER_ENTERED 모드
  // 셀 범위 고정: A1, C2:D4, C5:D7, A8, C8, D8
}

@Component
public class TelegramAdapter implements NotifyPort {
  // POST https://api.telegram.org/bot{token}/sendMessage
  // RestTemplate, 타임아웃 30초
  // TELEGRAM_BOT_TOKEN, TELEGRAM_CHAT_ID 환경변수
  // 메시지 포맷: n8n 기존 포맷 재현 (날짜, 매수/매도 목록, 현금잔고, 평단, 보유수량)
}

@Component
@RequiredArgsConstructor
public class FandingScheduler {
  private final ProcessTradingRecordUseCase useCase;

  @Scheduled(cron = "0 0 7 * * TUE-SAT", zone = "Asia/Seoul")
  public void run() { useCase.process(); }
}

- application.properties: spring.task.scheduling.enabled=true
- cron 표현식 및 timezone 절대 변경 금지
